import React, { createContext, useContext, useState, useEffect } from 'react';
import api from '../api/axios';
import { useAuth } from './AuthContext';

const GroupContext = createContext(null);

export function GroupProvider({ children }) {
  const { user } = useAuth();
  const [groups, setGroups] = useState([]);
  const [activeGroup, setActiveGroup] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (user) fetchGroups();
  }, [user]);

  const fetchGroups = async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/groups');
      setGroups(data);
      const savedGroupId = localStorage.getItem('activeGroupId');
      const found = savedGroupId ? data.find(g => g.id === parseInt(savedGroupId)) : null;
      setActiveGroup(found || data[0] || null);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const selectGroup = (group) => {
    setActiveGroup(group);
    localStorage.setItem('activeGroupId', group.id);
  };

  const createGroup = async (name, description) => {
    const { data } = await api.post('/groups', { name, description });
    setGroups(prev => [...prev, data]);
    return data;
  };

  const addMember = async (groupId, email) => {
    const { data } = await api.post(`/groups/${groupId}/members`, { email });
    await fetchGroups();
    return data;
  };

  const removeMember = async (groupId, memberId) => {
    await api.delete(`/groups/${groupId}/members/${memberId}`);
    await fetchGroups();
  };

  return (
    <GroupContext.Provider value={{
      groups, activeGroup, loading,
      selectGroup, createGroup, addMember, removeMember, fetchGroups
    }}>
      {children}
    </GroupContext.Provider>
  );
}

export const useGroup = () => useContext(GroupContext);
